import{_ as e,o as l,c as a,a2 as r}from"./chunks/framework.Pywvta2k.js";const x=JSON.parse('{"title":"小儿药证直诀","description":"","frontmatter":{},"headers":[],"relativePath":"tcm-data/03-宋金元/05-小儿药证直诀（钱乙）.md","filePath":"tcm-data/03-宋金元/05-小儿药证直诀（钱乙）.md","lastUpdated":1781084559000}'),n={name:"tcm-data/03-宋金元/05-小儿药证直诀（钱乙）.md"};function o(s,t,d,i,g,h){return l(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="小儿药证直诀" tabindex="-1">小儿药证直诀 <a class="header-anchor" href="#小儿药证直诀" aria-label="Permalink to &quot;小儿药证直诀&quot;">​</a></h1><blockquote><p>钱乙（约1032-1113年），山东郓州人 儿科之圣，六味地黄丸的创制者 代表作：《小儿药证直诀》</p></blockquote><hr><h2 id="一、基本信息" tabindex="-1">一、基本信息 <a class="header-anchor" href="#一、基本信息" aria-label="Permalink to &quot;一、基本信息&quot;">​</a></h2><ul><li><strong>字号</strong>：字仲阳</li><li><strong>生平</strong>：幼年丧母，父远游，由姑母抚养长大。早年以针灸成名，后专攻儿科</li><li><strong>代表著作</strong>：《小儿药证直诀》（由其弟子阎孝忠整理）</li><li><strong>学术地位</strong>：<strong>中医儿科鼻祖</strong>，&quot;儿科之圣&quot;</li></ul><hr><h2 id="二、核心理论" tabindex="-1">二、核心理论 <a class="header-anchor" href="#二、核心理论" aria-label="Permalink to &quot;二、核心理论&quot;">​</a></h2><h3 id="_1-小儿生理特点" tabindex="-1">1. 小儿生理特点 <a class="header-anchor" href="#_1-小儿生理特点" aria-label="Permalink to &quot;1. 小儿生理特点&quot;">​</a></h3><blockquote><p><strong>「小儿五脏六腑，成而未全，全而未壮。」</strong></p></blockquote><p>钱乙提出小儿生理的三个特点：</p><ul><li><strong>脏腑柔弱</strong>：五脏六腑尚未发育完全</li><li><strong>易虚易实</strong>：生病时变化快，虚证和实证可迅速转化</li><li><strong>易寒易热</strong>：体温调节能力差，容易受寒或化热</li></ul><h3 id="_2-五脏辨证-儿科专用" tabindex="-1">2. 五脏辨证（儿科专用） <a class="header-anchor" href="#_2-五脏辨证-儿科专用" aria-label="Permalink to &quot;2. 五脏辨证（儿科专用）&quot;">​</a></h3><p>钱乙将儿科疾病按五脏分类，各立补泻方：</p><table tabindex="0"><thead><tr><th style="text-align:left;">五脏</th><th style="text-align:left;">主证</th><th style="text-align:left;">补方</th><th style="text-align:left;">泻方</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>心</strong></td><td style="text-align:left;">惊悸、烦热</td><td style="text-align:left;">安神丸</td><td style="text-align:left;">导赤散</td></tr><tr><td style="text-align:left;"><strong>肝</strong></td><td style="text-align:left;">抽搐、目赤</td><td style="text-align:left;">补肾地黄丸（即六味）</td><td style="text-align:left;">泻青丸</td></tr><tr><td style="text-align:left;"><strong>脾</strong></td><td style="text-align:left;">腹泻、腹胀</td><td style="text-align:left;">益黄散</td><td style="text-align:left;">泻黄散</td></tr><tr><td style="text-align:left;"><strong>肺</strong></td><td style="text-align:left;">咳嗽、气喘</td><td style="text-align:left;">阿胶散</td><td style="text-align:left;">泻白散</td></tr><tr><td style="text-align:left;"><strong>肾</strong></td><td style="text-align:left;">发育迟缓、遗尿</td><td style="text-align:left;">六味地黄丸</td><td style="text-align:left;">无泻（肾无实证）</td></tr></tbody></table><h3 id="_3-六味地黄丸-钱乙最大的贡献" tabindex="-1">3. 六味地黄丸（钱乙最大的贡献） <a class="header-anchor" href="#_3-六味地黄丸-钱乙最大的贡献" aria-label="Permalink to &quot;3. 六味地黄丸（钱乙最大的贡献）&quot;">​</a></h3><p><strong>组成</strong>：熟地8钱、山萸肉4钱、山药4钱、泽泻3钱、丹皮3钱、茯苓3钱</p><ul><li>原为治疗小儿<strong>肾虚发育迟缓</strong>（五迟五软）</li><li>钱乙将《金匮》八味肾气丸去桂枝、附子，留下六味</li><li>后世成为<strong>滋阴补肾的第一方</strong></li><li>被广泛用于成人的肾阴虚证</li></ul><h3 id="_4-痘疹治法" tabindex="-1">4. 痘疹治法 <a class="header-anchor" href="#_4-痘疹治法" aria-label="Permalink to &quot;4. 痘疹治法&quot;">​</a></h3><p>钱乙对天花、水痘等儿科传染病有系统论述，提出&quot;凉血解毒&quot;的治疗原则。</p><hr><h2 id="三、代表方剂" tabindex="-1">三、代表方剂 <a class="header-anchor" href="#三、代表方剂" aria-label="Permalink to &quot;三、代表方剂&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">方名</th><th style="text-align:left;">组成</th><th style="text-align:left;">主治</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>六味地黄丸</strong></td><td style="text-align:left;">熟地、山萸、山药、泽泻、丹皮、茯苓</td><td style="text-align:left;">肾阴虚</td></tr><tr><td style="text-align:left;"><strong>导赤散</strong></td><td style="text-align:left;">生地、木通、甘草、竹叶</td><td style="text-align:left;">心经火热，口疮</td></tr><tr><td style="text-align:left;"><strong>泻白散</strong></td><td style="text-align:left;">桑白皮、地骨皮、甘草、粳米</td><td style="text-align:left;">肺热咳嗽</td></tr><tr><td style="text-align:left;"><strong>泻青丸</strong></td><td style="text-align:left;">当归、龙胆草、川芎、栀子、大黄、羌活、防风</td><td style="text-align:left;">肝热抽搐</td></tr><tr><td style="text-align:left;"><strong>益黄散</strong></td><td style="text-align:left;">陈皮、丁香、诃子、甘草、青皮</td><td style="text-align:left;">脾虚腹泻</td></tr><tr><td style="text-align:left;"><strong>白术散</strong></td><td style="text-align:left;">人参、白术、茯苓、甘草、木香、藿香、葛根</td><td style="text-align:left;">脾虚津亏</td></tr></tbody></table><hr><h2 id="四、经典名言" tabindex="-1">四、经典名言 <a class="header-anchor" href="#四、经典名言" aria-label="Permalink to &quot;四、经典名言&quot;">​</a></h2><blockquote><p><strong>「小儿五脏六腑，成而未全，全而未壮。」</strong></p></blockquote><blockquote><p><strong>「肾主虚，无实证。」</strong></p></blockquote><blockquote><p><strong>「小儿易虚易实，易寒易热。」</strong></p></blockquote><hr><h2 id="五、对后世的影响" tabindex="-1">五、对后世的影响 <a class="header-anchor" href="#五、对后世的影响" aria-label="Permalink to &quot;五、对后世的影响&quot;">​</a></h2><ul><li><strong>六味地黄丸</strong>是中医临床使用最广泛的基础方之一</li><li>儿科的&quot;五脏辨证&quot;体系影响了黄元御</li><li>钱乙的<strong>五脏补泻方</strong>直接启发了张元素（易水学派）的&quot;脏腑用药式&quot;</li></ul><hr><p><em>本条目为精简框架版。可扩展至儿科常见病专题、钱乙方剂现代应用等。</em></p>',32)])])}const u=e(n,[["render",o]]);export{x as __pageData,u as default};
